// ─── CURSOR ───
document.body.style.cursor = 'none';
const cursor     = document.getElementById('cursor');
const ring       = document.getElementById('cursor-ring');
const trailCanvas= document.getElementById('cursor-trail-canvas');
const tctx       = trailCanvas.getContext('2d');

// Size canvas
function resizeTrail() { trailCanvas.width = window.innerWidth; trailCanvas.height = window.innerHeight; }
resizeTrail(); window.addEventListener('resize', resizeTrail);

// Mouse state
let mx = -200, my = -200, rx = -200, ry = -200;

// Particle trail
const particles = [];
const COLORS = ['rgba(0,229,255,', 'rgba(15,143,255,', 'rgba(64,196,255,', 'rgba(255,255,255,'];

document.addEventListener('mousemove', e => {
  mx = e.clientX; my = e.clientY;
  cursor.style.left = mx + 'px'; cursor.style.top = my + 'px';

  // Spawn particle
  if (Math.random() > 0.35) {
    particles.push({
      x: mx, y: my,
      vx: (Math.random() - 0.5) * 1.2,
      vy: (Math.random() - 0.5) * 1.2,
      r:  Math.random() * 2.5 + 0.8,
      life: 1,
      decay: Math.random() * 0.04 + 0.025,
      color: COLORS[Math.floor(Math.random() * COLORS.length)]
    });
  }
});

// Ring follows with lag
function animateCursor() {
  rx += (mx - rx) * 0.12;
  ry += (my - ry) * 0.12;
  ring.style.left = rx + 'px';
  ring.style.top  = ry + 'px';

  // Draw trail
  tctx.clearRect(0, 0, trailCanvas.width, trailCanvas.height);
  for (let i = particles.length - 1; i >= 0; i--) {
    const p = particles[i];
    p.x  += p.vx; p.y  += p.vy;
    p.vy += 0.04; // gravity
    p.life -= p.decay;
    if (p.life <= 0) { particles.splice(i, 1); continue; }
    tctx.beginPath();
    tctx.arc(p.x, p.y, p.r * p.life, 0, Math.PI * 2);
    tctx.fillStyle = p.color + (p.life * 0.7) + ')';
    tctx.fill();
  }

  requestAnimationFrame(animateCursor);
}
animateCursor();

// Hover state
const hoverEls = 'a,button,.team-card,.event-card,.project-card,.blog-card,.discussion-card,.gallery-item,.ftm-vip-card,.ftm-member-card,.nav-links a';
document.querySelectorAll(hoverEls).forEach(el => {
  el.addEventListener('mouseenter', () => document.body.classList.add('cursor-hover'));
  el.addEventListener('mouseleave', () => document.body.classList.remove('cursor-hover'));
});

// Click burst
document.addEventListener('mousedown', () => {
  document.body.classList.add('cursor-click');
  // Burst particles
  for (let i = 0; i < 12; i++) {
    const angle = (i / 12) * Math.PI * 2;
    const speed = Math.random() * 3 + 1.5;
    particles.push({
      x: mx, y: my,
      vx: Math.cos(angle) * speed,
      vy: Math.sin(angle) * speed,
      r:  Math.random() * 3 + 1,
      life: 1,
      decay: Math.random() * 0.03 + 0.025,
      color: COLORS[Math.floor(Math.random() * COLORS.length)]
    });
  }
});
document.addEventListener('mouseup', () => document.body.classList.remove('cursor-click'));

// Hide/show on leave/enter window
document.addEventListener('mouseleave', () => { cursor.style.opacity='0'; ring.style.opacity='0'; });
document.addEventListener('mouseenter', () => { cursor.style.opacity='1'; ring.style.opacity='1'; });

// ─── STAR FIELD (INTRO) ───
const sc = document.getElementById('star-canvas');
const sctx = sc.getContext('2d');
function resizeStar() { sc.width = window.innerWidth; sc.height = window.innerHeight; }
resizeStar(); window.addEventListener('resize', resizeStar);
const STARS = Array.from({length:180}, () => ({ x:Math.random(), y:Math.random(), r:Math.random()*1.4, speed:Math.random()*0.0003+0.0001, op:Math.random()*0.7+0.1, tp:Math.random()*Math.PI*2, ts:Math.random()*0.02+0.005 }));
(function drawStar() {
  sctx.clearRect(0,0,sc.width,sc.height);
  STARS.forEach(s => {
    s.tp+=s.ts;
    const a = s.op*(0.5+0.5*Math.sin(s.tp));
    sctx.beginPath(); sctx.arc(s.x*sc.width, s.y*sc.height, s.r, 0, Math.PI*2);
    sctx.fillStyle=`rgba(160,210,255,${a})`; sctx.fill();
    s.y-=s.speed; if(s.y<0){s.y=1;s.x=Math.random();}
  });
  requestAnimationFrame(drawStar);
})();

// ─── HERO CANVAS (particle field) ───
const hc = document.getElementById('hero-canvas');
const hctx = hc.getContext('2d');
function resizeHero() { hc.width = hc.parentElement.offsetWidth; hc.height = hc.parentElement.offsetHeight; }
resizeHero(); window.addEventListener('resize', resizeHero);
const HPARTS = Array.from({length:60}, () => ({ x:Math.random(), y:Math.random(), r:Math.random()*1.5+0.5, vx:(Math.random()-0.5)*0.0002, vy:(Math.random()-0.5)*0.0002, op:Math.random()*0.4+0.1 }));
(function drawHero() {
  hctx.clearRect(0,0,hc.width,hc.height);
  // Draw connections
  HPARTS.forEach((p,i) => {
    HPARTS.slice(i+1).forEach(q => {
      const dx=(p.x-q.x)*hc.width, dy=(p.y-q.y)*hc.height;
      const d=Math.sqrt(dx*dx+dy*dy);
      if(d<120){ hctx.beginPath(); hctx.moveTo(p.x*hc.width,p.y*hc.height); hctx.lineTo(q.x*hc.width,q.y*hc.height); hctx.strokeStyle=`rgba(15,143,255,${0.08*(1-d/120)})`; hctx.stroke(); }
    });
  });
  HPARTS.forEach(p => {
    hctx.beginPath(); hctx.arc(p.x*hc.width, p.y*hc.height, p.r, 0, Math.PI*2);
    hctx.fillStyle=`rgba(64,196,255,${p.op})`; hctx.fill();
    p.x+=p.vx; p.y+=p.vy;
    if(p.x<0)p.x=1; if(p.x>1)p.x=0; if(p.y<0)p.y=1; if(p.y>1)p.y=0;
  });
  requestAnimationFrame(drawHero);
})();

