// ─── NAVIGATION ───
function scrollToSection(id, e) {
  if (e) e.preventDefault();
  document.getElementById(id)?.scrollIntoView({behavior:'smooth'});
  // Close mobile menu if open
  const nl = document.getElementById('navLinks');
  if (nl.classList.contains('mobile-open')) {
    nl.classList.remove('mobile-open');
    nl.removeAttribute('style');
  }
}
window.addEventListener('scroll', () => {
  document.getElementById('scrollTop').classList.toggle('visible', window.scrollY > 400);
  const sections = ['hero','about','events','team','projects','blog','gallery','join','contact'];
  const links = document.querySelectorAll('.nav-links a');
  let current = '';
  sections.forEach(id => { const el = document.getElementById(id); if(el && window.scrollY >= el.offsetTop - 100) current = id; });
  links.forEach(a => { a.classList.remove('active'); if(a.getAttribute('onclick')?.includes(current)) a.classList.add('active'); });
});

function toggleMobileMenu() {
  const nl = document.getElementById('navLinks');
  const isOpen = nl.classList.contains('mobile-open');
  if (isOpen) {
    nl.classList.remove('mobile-open');
    nl.removeAttribute('style');
  } else {
    nl.classList.add('mobile-open');
    nl.style.display = 'flex';
    nl.style.flexDirection = 'column';
    nl.style.position = 'fixed';
    nl.style.top = '64px';
    nl.style.left = '0';
    nl.style.right = '0';
    nl.style.background = 'var(--bg)';
    nl.style.padding = '20px';
    nl.style.borderBottom = '1px solid var(--border)';
    nl.style.zIndex = '999';
  }
}

// ─── STATS COUNTER ───
function animateCounter(el) {
  const target = parseInt(el.dataset.target);
  let current = 0;
  const step = Math.ceil(target / 60);
  const timer = setInterval(() => {
    current = Math.min(current + step, target);
    el.textContent = current;
    if(current >= target) clearInterval(timer);
  }, 25);
}

// ─── SCROLL REVEAL + COUNTER ───
const observer = new IntersectionObserver((entries) => {
  entries.forEach(e => {
    if(e.isIntersecting) {
      e.target.classList.add('visible');
      e.target.querySelectorAll('.counter').forEach(animateCounter);
    }
  });
}, {threshold: 0.15});
document.querySelectorAll('.fade-in').forEach(el => observer.observe(el));



