// ─── VOTE ───
function vote(btn) {
  if (btn.dataset.voted) return;
  btn.dataset.voted = '1';
  const countEl = btn.parentElement.querySelector('.disc-vote-count');
  countEl.textContent = parseInt(countEl.textContent) + 1;
  btn.style.color = 'var(--cyan)';
  btn.style.borderColor = 'var(--cyan)';
  // Disable the downvote sibling to prevent conflicts
  const downBtn = btn.parentElement.querySelector('[data-dir="down"]');
  if (downBtn) downBtn.disabled = true;
}
function downvote(btn) {
  if (btn.dataset.voted) return;
  btn.dataset.voted = '1';
  const countEl = btn.parentElement.querySelector('.disc-vote-count');
  const cur = parseInt(countEl.textContent);
  countEl.textContent = Math.max(0, cur - 1);
  btn.style.color = '#f87171';
  btn.style.borderColor = '#f87171';
  const upBtn = btn.parentElement.querySelector('[data-dir="up"]');
  if (upBtn) upBtn.disabled = true;
}

// ─── POST DISCUSSION ───
function escapeHtml(str) {
  return str.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;').replace(/'/g,'&#039;');
}
function postDiscussion() {
  const title = document.getElementById('discTitle').value.trim();
  const body = document.getElementById('discBody').value.trim();
  if(!title || !body) { alert('Please fill in title and body!'); return; }
  const card = document.createElement('div');
  card.className = 'discussion-card';
  card.style.borderColor = 'rgba(0,229,255,0.3)';
  card.innerHTML = `
    <div class="disc-votes"><button class="disc-vote-btn" data-dir="up" onclick="vote(this)">▲</button><div class="disc-vote-count">1</div><button class="disc-vote-btn" data-dir="down" onclick="downvote(this)">▼</button></div>
    <div class="disc-content">
      <div class="disc-tags"><span class="disc-tag">New</span></div>
      <div class="disc-title">${escapeHtml(title)}</div>
      <div class="disc-body">${escapeHtml(body)}</div>
      <div class="disc-meta"><span>👤 You</span><span>💬 0 replies</span><span>🕐 Just now</span></div>
    </div>`;
  document.getElementById('discussionList').prepend(card);
  document.getElementById('discTitle').value = '';
  document.getElementById('discBody').value = '';
  showModal('💬', 'Discussion Posted!', 'Your discussion is now live. Other members can reply and upvote.');
}

// ─── OPEN GOOGLE FORM PRE-FILLED ───
function openGForm() {
  const phone   = document.getElementById('f-phone').value.trim();
  const roll    = document.getElementById('f-roll').value.trim();
  const email   = document.getElementById('f-email').value.trim();
  const branch  = document.getElementById('f-branch').value;
  const section = document.getElementById('f-section').value;
  const why     = document.getElementById('f-why').value.trim();

  // Validate required fields
  let valid = true;
  ['f-phone','f-roll','f-email','f-branch','f-section','f-why'].forEach(id => {
    const el = document.getElementById(id);
    if (!el.value.trim()) {
      el.style.borderColor = '#f87171';
      setTimeout(() => el.style.borderColor = '', 2500);
      valid = false;
    }
  });
  if (!valid) { alert('Please fill in all required fields first.'); return; }

  // Build pre-filled Google Form URL
  // NOTE: Replace these entry IDs with the real ones from your Google Form (see instructions)
  const base = 'https://docs.google.com/forms/d/e/1FAIpQLSepx0Fz5hAmPgfyMcDFrF1Z4QwwHQ3h8jB_BEz0spTIMv3GTg/viewform';
  const name  = document.getElementById('f-name').value.trim();
  const params = new URLSearchParams();
  if (name)    params.set('usp', 'pp_url'); // keeps URL clean
  // Open the form directly — user clicks Submit there
  window.open(base + '?' + params.toString(), '_blank');
}

function sendMessage() {
  const contactSection = document.getElementById('contact');
  const inputs = contactSection.querySelectorAll('input[type="text"], input[type="email"], textarea');
  let allFilled = true;
  inputs.forEach(inp => {
    if (!inp.value.trim()) {
      allFilled = false;
      inp.style.borderColor = '#f87171';
      setTimeout(() => inp.style.borderColor = '', 2000);
    }
  });
  if (!allFilled) { alert('Please fill in all fields before sending.'); return; }
  showModal('✉️', 'Message Sent!', "Thank you for reaching out. Our team will reply to your email within 24 hours.");
}

